// ============================================================
// RHODENSE CALCIO - Logo embedded
// ============================================================
const LOGO_RHODENSE = 'data:image/png;base64,';

(function() {
  function applyLogo() {
    document.querySelectorAll('#loading-img, #header-logo').forEach(img => {
      img.src = LOGO_RHODENSE;
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', applyLogo);
  } else {
    applyLogo();
  }
  const obs = new MutationObserver(applyLogo);
  obs.observe(document.documentElement, { childList: true, subtree: true });
  setTimeout(applyLogo, 500);
  setTimeout(applyLogo, 1500);
})();
